#include <bits/stdc++.h>using namespace std;typedef long long ll;int main() {    ll t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<ll> a(n,0);        for(int i=0;i<n;i++){            cin>>a[i];        }        if(n==1){            cout<<1<<endl;        }        else{            for(int i=0;i<n;i++){                cout<<2<<" ";            }            cout<<endl;        }    }    return 0;}